// frontend/src/hooks/useToken.ts
import { useState, useEffect } from "react";
import { ethers, BigNumber } from "ethers";

const CONTRACT_ADDRESS = "0x0c298cD0838BF8e151CDA0Ae19C3B698b453632F";

const ABI = [ /* paste your full ABI here */ ];

export const useToken = (signer: ethers.Signer | null) => {
  const [contract, setContract] = useState<ethers.Contract | null>(null);

  useEffect(() => {
    if (!signer) return;
    const token = new ethers.Contract(CONTRACT_ADDRESS, ABI, signer);
    setContract(token);
  }, [signer]);

  // Read functions
  const balanceOf = async (address: string): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.balanceOf(address);
  };

  const totalSupply = async (): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.totalSupply();
  };

  const maxSupply = async (): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.MAX_SUPPLY();
  };

  const faucetCooldown = async (): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.FAUCET_COOLDOWN();
  };

  const lastRequestTime = async (user: string): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.lastRequestTime(user);
  };

  const getRemainingCooldown = async (user: string): Promise<BigNumber> => {
    if (!contract) return BigNumber.from(0);
    return await contract.getRemainingCooldown(user);
  };

  const decimals = async (): Promise<number> => {
    if (!contract) return 18;
    return await contract.decimals();
  };

  const name = async (): Promise<string> => {
    if (!contract) return "";
    return await contract.name();
  };

  const symbol = async (): Promise<string> => {
    if (!contract) return "";
    return await contract.symbol();
  };

  // Write functions
  const requestTokens = async () => {
    if (!contract) return;
    const tx = await contract.requestTokens();
    await tx.wait();
  };

  const mint = async (to: string, amount: BigNumber) => {
    if (!contract) return;
    const tx = await contract.mint(to, amount);
    await tx.wait();
  };

  const transfer = async (to: string, amount: BigNumber) => {
    if (!contract) return;
    const tx = await contract.transfer(to, amount);
    await tx.wait();
  };

  return {
    contract,
    balanceOf,
    totalSupply,
    maxSupply,
    faucetCooldown,
    lastRequestTime,
    getRemainingCooldown,
    decimals,
    name,
    symbol,
    requestTokens,
    mint,
    transfer,
  };
};
